#include <stdio.h>
#include <string.h>

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int adj[6][2] = {{1, 2}, {3, 2}, {4, 2}, {5, 2}, {1, 2}, {5, 2}};
        char s[10001];
        scanf("%s", s);
        int curr = 1, n = strlen(s);

        for (int i = 0; i < n; i++)
            curr = adj[curr][s[i] - '0'];

        if (curr == 5)
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}

