public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int adj[][] = {{1, 2}, {3, 2}, {4, 2}, {5, 2}, {1, 2}, {5, 2}};
            String s = sc.next();
            int curr = 1, n = s.length();

            for (int i = 0; i < n; i++)
                curr = adj[curr][s.charAt(i) - '0'];

            if (curr == 5)
                System.out.println("YES");
            else
                System.out.println("NO");
        }
    }
}

